const fs = require('fs');
const path = require('path');

// Function to generate or update package-lock.json
function generatePackageLock() {
  const packageJsonPath = path.join(__dirname, 'package.json');
  
  if (!fs.existsSync(packageJsonPath)) {
    console.error('package.json not found in the current directory.');
    return;
  }

  // Run npm install to generate or update package-lock.json
  const { exec } = require('child_process');
  exec('npm install', (error, stdout, stderr) => {
    if (error) {
      console.error(`Error generating package-lock.json: ${stderr}`);
      return;
    }
    console.log(stdout);
    console.log('package-lock.json generated or updated successfully.');
  });
}

// Call the function to generate/update package-lock.json
generatePackageLock();